api.code:
// 使用 fetch 进行 API 调用（异步）
return (async () => {
  const { url, method = 'GET' } = params

  try {
    const response = await fetch(url, {
      method,
      headers: {
        'Content-Type': 'application/json'
      }
    })

    const data = await response.json()
    return data
  } catch (error) {
    throw new Error(`API 请求失败: ${error.message}`)
  }
})()

